import React from 'react'
import '../../styles/header.css'
import Modal from 'react-modal'
import { useState } from 'react'
import FacebookLogin from 'react-facebook-login';
import GoogleLogin from 'react-google-login';

const responseGoogle = (response) => {
  console.log(response);
}
const responseFacebook = (response) => {
  console.log(response);
}

const customStyles = {
  content: {
    top: '50%',
    left: '50%',
    right: 'auto',
    bottom: 'auto',
    marginRight: '-50%',
    transform: 'translate(-50%, -50%)',
  },
};

export default function Header() {

const [isLoginModalOpen, setLoginModal] =useState(false)
const [isAccountModalOpen, setAccountModal] =useState(false)

  return (
    <div className='header'>
        <div className="s-logo">
            <span>e!</span>
        </div>
         <div className='btn-group login-block'>
           <span className='login' onClick={()=>setLoginModal(true)}>Login</span>
           <span className='signUp'  onClick={()=>setAccountModal(true)}>Create an account</span>
         </div>
       <Modal 
       isOpen={isLoginModalOpen}
       style={customStyles}
       >
        <h2>Login Modal
          <button onClick={()=>setLoginModal(false)} className='btn btn-danger' >X</button>
        </h2>
         
         <form>
          <input placeholder='enter yor email' type="text"/><br/>
          <input placeholder='enter yor password' type="password"/><br/>
          <button>Login</button>
          <br/> 
         </form>

        <FacebookLogin
    appId="1866794680378266"
    fields="name,email,picture"
    cssClass="my-facebook-button-class"
    icon="fa-facebook"
    callback={()=>responseFacebook}
    // onClick={componentClicked}
    // callback={responseFacebook} 
    />
    <GoogleLogin
    clientId="658977310896-knrl3gka66fldh83dao2rhgbblmd4un9.apps.googleusercontent.com"
    buttonText="Login with Google"
    response={()=>responseGoogle}
   
  />,
       </Modal>
       <Modal 
       isOpen={isAccountModalOpen}
       style={customStyles}
       >
        <h2>Create Zomato Account
          <button onClick={()=>setAccountModal(false)} className='btn btn-danger' >X</button>
        </h2>
         
         <form>
          <input placeholder='enter yor email' type="text"/><br/>
          <input placeholder='enter yor password' type="password"/><br/>
          <button>Create Account</button>
          <br/> 
         </form>

       </Modal>
    </div>
  )
}
